VALUES
  ('retired-d0d1b9a2-moex-00420', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '某養雞場之營運模式係待雞長成後，分別將雞隻各部位分別出售給下游業者。試問在計算雞 隻各部位之成本時，雞隻之養殖成本係屬於下列何者？', '["可免成本", "聯合成本", "機會成本", "行銷成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00421', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '某公司以聯合成本$135,000生產聯合產品X及Y，二種產品均可進一步加工後再出售。有關 進一步加工相關資料彙整如下： X產品 Y產品 再加工成本 $500,000 $144,000 單位數 分離點 9,600 2,400 再加工後 8,400 2,400 單位售價 分離點 $144 $264 再加工後 $216 $360 若該公司極大化利潤，則有關X產品及Y產品進一步加工之決策，下列何者正確？', '["若採用固定毛利率淨變現價值法（Constant gross-margin percentage NRVmethod），則應進 一步加工X與Y", "若採用淨變現價值法（Netrealizablevaluemethod），則不應進一步加工X與Y", "若採用產量法（Physicalunitsmethod），則應進一步加工X但不進一步加工Y", "若採用分離點售價法（Salesvalueatsplitoffmethod），則不應進一步加工X但進一步加工Y 13640"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00422', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '下列何者為製造成本的定義？', '["直接材料＋製造費用", "直接人工＋製造費用", "加工成本＋製造費用", "主要成本＋製造費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00423', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司生產冰淇淋，員工運用迴歸分析估計公司製造冰淇淋的加工成本函數如下： Variable 係數 標準誤 t-值 常數10 7.194 1.39 自變數 1（機器小時） 21 9.174 2.28 自變數 2（生產次數） 12.605 6.012 2.09 R2=0.82 假設明年有5批冰淇淋訂單，總共需要製造1,000個冰淇淋，每個冰淇淋材料成本為$20，製 造需要 20 分鐘的機器時間，10 分鐘的人工，根據上述成本函數，請問公司每個冰淇淋的製 造成本為何？', '["$25.279", "$27.073", "$43.682", "$63.605"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00424', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司產銷電動車，目前自製零件X，預計每月產製13,000單位之製造成本為$3,588,000（包 含直接原料$1,196,000，直接人工$299,000，變動製造費用$897,000，固定製造費用$1,196,000）。 若外購 X 零件，固定製造費用可節省 4%。甲公司外購 X 零件願意支付之最高採購單價為 何？', '["184.00", "187.68", "230.00", "233.68"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00425', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '若公司對副產品採用不分攤聯合成本的會計處理，公司當年度期末存貨較期初存貨增加時， 在下列各種副產品會計處理方法中，何者會導致公司的純益最低？', '["副產品的收入列為其他收入", "副產品的收入列為銷貨收入", "副產品的收入列為主產品生產成本的減項", "副產品的收入列為主產品銷貨成本的減項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00426', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '某公司生產甲產品，直接原料於製程結束時投入，今年相關資料如下： 期初在製品存貨 145,000單位 直接原料（完工程度 0%） 加工成本（完工程度 80%） 本期投入製造 ？單位 完工並轉出 595,000單位 期末在製品存貨 100,000單位 直接原料（完工程度 0%） 加工成本（完工程度 90%） 請問在先進先出法下，計算單位加工成本所需之加工成本約當數量為何？', '["470,000", "482,690", "569,000", "571,900"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
