  ('retired-d0d1b9a2-moex-00428', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司僱用之專業人工包括15位全職員工與10位工讀生。依專業人工小時數為基礎分攤間 接成本。下列為當年度資訊： 預算 實際 年度間接成本 $200,000 $300,000 每位全職員工每小時工資率 $30 $33 每位工讀生每小時工資率 $5 $6 年度專業人工小時數合計 50,000直接人工小時 60,000直接人工小時 某客戶使用1,000個專業人工小時。在正常成本法下，服務該客戶之成本為何？', '["$33,600", "$29,800", "$39,000", "$43,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
